import { useEffect } from "react";
import { Container, Row, Col, Card, CardBody, CardTitle, CardText, Button, Spinner } from "reactstrap";
import { useDispatch, useSelector } from "react-redux";
import { getTasks, deleteTask } from "../Features/TaskSlice";
import { useNavigate } from "react-router-dom";

const Home = () => {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  
  // جلب البيانات من الـ Redux
  const { items, isLoading } = useSelector((state) => state.tasks);
  const user = useSelector((state) => state.users.user);

  useEffect(() => {
    // إذا لم يكن هناك مستخدم مسجل، أعده لصفحة اللوجن
    if (!user?.email) {
      navigate("/login");
    } else {
      dispatch(getTasks());
    }
  }, [dispatch, user, navigate]);

  const handleDelete = (id) => {
    if (window.confirm("Are you sure you want to delete this task?")) {
      dispatch(deleteTask(id));
    }
  };

  return (
    <Container className="mt-4 pb-5">
      <Row className="align-items-center mb-5 p-4 bg-white rounded-4 shadow-sm border-0">
        <Col>
          <h1 className="fw-bold mb-1">Welcome, {user?.name || "User"}!</h1>
          <p className="text-muted mb-0">Here are your daily life topics and tasks:</p>
        </Col>
        <Col className="text-end">
          <Button color="success" onClick={() => navigate("/add-task")}>+ Add New Task</Button>
        </Col>
      </Row>

      {isLoading ? (
        <div className="text-center"><Spinner color="primary" /></div>
      ) : (
        <Row>
          {items.length > 0 ? items.map((task) => (
            <Col md="4" key={task._id} className="mb-4">
              <Card className="shadow-sm border-0">
                <CardBody>
                  <CardTitle tag="h5" className="fw-bold">{task.title}</CardTitle>
                  <CardText className="text-muted">{task.description}</CardText>
                  <div className="d-flex justify-content-between align-items-center">
                    <small className="text-primary font-weight-bold">{task.priority}</small>
                    <span className={`badge ${task.status === 'Completed' ? 'bg-success' : 'bg-warning'}`}>
                      {task.status}
                    </span>
                  </div>
                  <hr />
                  <div className="d-flex justify-content-around">
                    <Button color="outline-primary" size="sm" onClick={() => navigate(`/updateTask/${task._id}`)}>Edit</Button>
                    <Button color="outline-danger" size="sm" onClick={() => handleDelete(task._id)}>Delete</Button>
                  </div>
                </CardBody>
              </Card>
            </Col>
          )) : (
            <Col className="text-center mt-5">
              <h3>No tasks found. Start by adding some!</h3>
            </Col>
          )}
        </Row>
      )}
    </Container>
  );
};

export default Home;
